```tsx
import { useState, useEffect, useCallback } from ''react''

function UserList() {
  const [users, setUsers] = useState<User[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetchUsers().then(data => {
      setUsers(data)
      setLoading(false)
    })
  }, [])

  return (
    <div>
      {loading ? <Spin /> : users.map(u => <UserCard key={u.id} user={u} />)}
    </div>
  )
}
